class Solution:
    def minimumDistance(self, points):
        n = len(points)
        best = float('inf')
        for skip in range(n):
            cur_max = 0
            for i in range(n):
                if i == skip: continue
                for j in range(i+1, n):
                    if j == skip: continue
                    d = abs(points[i][0]-points[j][0]) + abs(points[i][1]-points[j][1])
                    cur_max = max(cur_max, d)
            best = min(best, cur_max)
        return best

