class Solution:
    def minimumDistance(self, points):
        # u = x+y, v = x-y; max Manhattan = max(max_u-min_u, max_v-min_v)
        n = len(points)
        us = sorted((x+y, i) for i, (x, y) in enumerate(points))
        vs = sorted((x-y, i) for i, (x, y) in enumerate(points))

        def max_dist_without(skip):
            # max u span
            max_u = us[-1][0] if us[-1][1] != skip else us[-2][0]
            min_u = us[0][0] if us[0][1] != skip else us[1][0]
            # max v span
            max_v = vs[-1][0] if vs[-1][1] != skip else vs[-2][0]
            min_v = vs[0][0] if vs[0][1] != skip else vs[1][0]
            return max(max_u - min_u, max_v - min_v)

        # candidates: the four extremal point indices
        candidates = {us[0][1], us[-1][1], vs[0][1], vs[-1][1]}
        return min(max_dist_without(s) for s in candidates)

