var minimumDistance = function(points) {
    const n = points.length;
    const us = points.map(([x,y], i) => [x+y, i]).sort((a,b) => a[0]-b[0]);
    const vs = points.map(([x,y], i) => [x-y, i]).sort((a,b) => a[0]-b[0]);

    function maxDistWithout(skip) {
        const maxU = us[n-1][1] !== skip ? us[n-1][0] : us[n-2][0];
        const minU = us[0][1] !== skip ? us[0][0] : us[1][0];
        const maxV = vs[n-1][1] !== skip ? vs[n-1][0] : vs[n-2][0];
        const minV = vs[0][1] !== skip ? vs[0][0] : vs[1][0];
        return Math.max(maxU - minU, maxV - minV);
    }

    const candidates = new Set([
        us[0][1], us[n-1][1], vs[0][1], vs[n-1][1]
    ]);
    let best = Infinity;
    for (const s of candidates) best = Math.min(best, maxDistWithout(s));
    return best;
};
